package com.hzltd.module.erplus.ai.mas.spi.llm;

/**
 * Framework-agnostic LLM Client interface for MAS engine interactions.
 */
public interface MasLlmClient {

    /**
     * Send a generation request using the history context.
     * 
     * @param history The conversation history up to this point
     * @return The response text generated by the language model
     */
    String chat(MasMessageHistory history);

    /**
     * Standard generation request with a single text prompt.
     * 
     * @param prompt User's direct query
     * @return The response text generated by the language model
     */
    String chat(String prompt, String sessionId);
}
